/**
 * Parity tests for scripts/lib/rpi-formula.mjs
 *
 * Fixtures sourced from two independent references:
 *   1. Manually computed from Daniels/Gilbert formula (verified algebraically)
 *   2. BLUF claims in existing page configs (apps/web/app/tools/[tool]/[distance]/page.tsx)
 *      — those values were generated by the live production API (Python rpi_calculator.py)
 *
 * ALL expected values precomputed by hand and cross-checked against page BLUFs.
 * This script must exit 0 before any data generation runs.
 *
 * Usage: node scripts/test-rpi-formula.mjs
 */
import { readFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import {
  calculateRpi,
  calculateTrainingPaces,
  calculateEquivalentRaceTime,
  formatPaceMi,
  formatPaceKm,
  formatTime,
} from './lib/rpi-formula.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));

let passed = 0;
let failed = 0;

function assert(name, actual, expected, toleranceOrExact) {
  let ok;
  if (typeof toleranceOrExact === 'number' && toleranceOrExact > 0) {
    ok = Math.abs(actual - expected) <= toleranceOrExact;
  } else {
    ok = actual === expected;
  }
  if (ok) {
    passed++;
    console.log(`  ✓  ${name}: ${actual}`);
  } else {
    failed++;
    const suffix =
      typeof toleranceOrExact === 'number' && toleranceOrExact > 0
        ? ` ± ${toleranceOrExact}`
        : '';
    console.error(`  ✗  ${name}: expected "${expected}${suffix}", got "${actual}"`);
  }
}

// ============================================================================
// SECTION 1: RPI from race time
// Expected values independently computed from Daniels formula + confirmed
// against BLUF strings in existing page configs (which were API-generated).
// ============================================================================

console.log('\n=== Section 1: RPI from race time ===\n');

// 20:00 5K → page BLUF: "RPI 49.8"
assert('20:00 5K RPI', calculateRpi(5000, 1200), 49.8, 0.1);

// 25:00 5K → page BLUF: "RPI 38.3"
assert('25:00 5K RPI', calculateRpi(5000, 1500), 38.3, 0.1);

// 45:00 10K → page BLUF: "RPI 45.3"
assert('45:00 10K RPI', calculateRpi(10000, 2700), 45.3, 0.1);

// 50:00 10K → page BLUF: "RPI 40.0"
assert('50:00 10K RPI', calculateRpi(10000, 3000), 40.0, 0.1);

// 1:45:00 half → page BLUF: "RPI 42.6"
assert('1:45 half RPI', calculateRpi(21097.5, 6300), 42.6, 0.1);

// 2:00:00 half → page BLUF: "RPI 36.5"
assert('2:00 half RPI', calculateRpi(21097.5, 7200), 36.5, 0.1);

// 3:30:00 marathon → page BLUF: "RPI 44.6"
assert('3:30 marathon RPI', calculateRpi(42195, 12600), 44.6, 0.1);

// 4:00:00 marathon → page BLUF: "RPI 37.9"
assert('4:00 marathon RPI', calculateRpi(42195, 14400), 37.9, 0.1);

// ============================================================================
// SECTION 2: Training paces from RPI
// Expected values: page BLUF strings (API-generated, confirmed by hand calc).
// Using the API-stated RPI as input (not the recomputed one) to match exactly.
// ============================================================================

console.log('\n=== Section 2: Training paces from RPI ===\n');

// 20:00 5K runner: RPI 49.8
// page BLUF: easy 8:29/mi, threshold 6:49/mi, interval 5:58/mi
const p20_5k = calculateTrainingPaces(49.8);
assert('RPI 49.8 easy/mi',      p20_5k.easy.mi,      '8:29');
assert('RPI 49.8 threshold/mi', p20_5k.threshold.mi, '6:49');
assert('RPI 49.8 interval/mi',  p20_5k.interval.mi,  '5:58');

// 25:00 5K runner: RPI 38.3
// page BLUF: easy 10:15/mi, threshold 8:02/mi
const p25_5k = calculateTrainingPaces(38.3);
assert('RPI 38.3 easy/mi',      p25_5k.easy.mi,      '10:15');
assert('RPI 38.3 threshold/mi', p25_5k.threshold.mi, '8:02');

// 45:00 10K runner: RPI 45.3
// page BLUF: easy 9:02/mi, threshold 7:13/mi, interval 6:19/mi
const p45_10k = calculateTrainingPaces(45.3);
assert('RPI 45.3 easy/mi',      p45_10k.easy.mi,      '9:02');
assert('RPI 45.3 threshold/mi', p45_10k.threshold.mi, '7:13');
assert('RPI 45.3 interval/mi',  p45_10k.interval.mi,  '6:19');

// 50:00 10K runner: RPI 40.0
// page BLUF: easy 9:54/mi, threshold 7:47/mi
const p50_10k = calculateTrainingPaces(40.0);
assert('RPI 40.0 easy/mi',      p50_10k.easy.mi,      '9:54');
assert('RPI 40.0 threshold/mi', p50_10k.threshold.mi, '7:47');

// 3:30 marathon: RPI 44.6
// page BLUF: easy 9:08/mi, threshold 7:17/mi, interval 6:23/mi
const p330_m = calculateTrainingPaces(44.6);
assert('RPI 44.6 easy/mi',      p330_m.easy.mi,      '9:08');
assert('RPI 44.6 threshold/mi', p330_m.threshold.mi, '7:17');
assert('RPI 44.6 interval/mi',  p330_m.interval.mi,  '6:23');

// 4:00 marathon: RPI 37.9
// page BLUF: easy 10:20/mi, threshold 8:05/mi
const p400_m = calculateTrainingPaces(37.9);
assert('RPI 37.9 easy/mi',      p400_m.easy.mi,      '10:20');
assert('RPI 37.9 threshold/mi', p400_m.threshold.mi, '8:05');

// ============================================================================
// SECTION 3: Equivalency — internal consistency
// The binary search must reproduce a ~matching RPI when the equivalent
// time is fed back through the RPI formula.
// ============================================================================

console.log('\n=== Section 3: Equivalency round-trip consistency ===\n');

// For each equivalency: feed RPI → get equivalent time → feed back → should match RPI
const EQUIV_CASES = [
  { rpi: 49.8, dist: 5000,    label: '5K' },
  { rpi: 49.8, dist: 42195,   label: 'Marathon' },
  { rpi: 45.3, dist: 21097.5, label: 'Half' },
  { rpi: 37.9, dist: 10000,   label: '10K' },
  { rpi: 62.0, dist: 5000,    label: '5K elite' },
  { rpi: 30.0, dist: 42195,   label: 'Marathon slow' },
];

for (const { rpi, dist, label } of EQUIV_CASES) {
  const equiv = calculateEquivalentRaceTime(rpi, dist);
  if (!equiv) {
    failed++;
    console.error(`  ✗  RPI ${rpi} → ${label} equivalency: returned null`);
    continue;
  }
  const backRpi = calculateRpi(dist, equiv.timeSeconds);
  assert(
    `RPI ${rpi} → ${label} (${equiv.timeFormatted}) → back-RPI`,
    backRpi,
    rpi,
    0.2
  );
}

// ============================================================================
// SECTION 4: Format utilities
// ============================================================================

console.log('\n=== Section 4: Format utilities ===\n');

assert('formatPaceMi(509)',  formatPaceMi(509),  '8:29');
assert('formatPaceMi(409)',  formatPaceMi(409),  '6:49');
assert('formatPaceMi(615)',  formatPaceMi(615),  '10:15');
assert('formatPaceMi(482)',  formatPaceMi(482),  '8:02');
assert('formatPaceMi(542)',  formatPaceMi(542),  '9:02');
assert('formatPaceMi(433)',  formatPaceMi(433),  '7:13');
assert('formatTime(3600)',   formatTime(3600),   '1:00:00');
assert('formatTime(1799)',   formatTime(1799),   '29:59');
assert('formatTime(12600)',  formatTime(12600),  '3:30:00');
assert('formatTime(14399)',  formatTime(14399),  '3:59:59');

// ============================================================================
// SECTION 5: Cross-check vs existing training-pace-tables.json (spot check)
// ============================================================================

console.log('\n=== Section 5: Cross-check vs existing training-pace-tables.json ===\n');

try {
  const DATA_DIR = join(__dirname, '..', 'apps', 'web', 'data');
  const existingPaces = JSON.parse(
    readFileSync(join(DATA_DIR, 'training-pace-tables.json'), 'utf8')
  );

  // Spot-check 3 rows from the existing API-generated file
  const checks = [
    { distKey: '5k',    raceTime: '20:00', raceSec: 1200 },
    { distKey: '10k',   raceTime: '45:00', raceSec: 2700 },
    { distKey: 'marathon', raceTime: '3:30:00', raceSec: 12600 },
  ];

  for (const { distKey, raceTime, raceSec } of checks) {
    const row = existingPaces[distKey]?.rows?.find(r => r.raceTimeSeconds === raceSec);
    if (!row) {
      console.warn(`  ⚠  ${distKey} ${raceTime}: row not found in existing data (skipping)`);
      continue;
    }

    const myRpi = calculateRpi(
      existingPaces[distKey].distanceMeters,
      raceSec
    );
    const apiRpi = row.rpi;
    // Allow ±0.2 tolerance (API may use slightly different rounding)
    assert(
      `${distKey} ${raceTime} RPI (mine=${myRpi} vs API=${apiRpi})`,
      myRpi,
      apiRpi,
      0.2
    );

    const myPaces = calculateTrainingPaces(myRpi);
    const apiEasy = row.paces?.easy?.mi;
    if (apiEasy) {
      // Convert apiEasy "MM:SS or slower" → just "MM:SS"
      const apiEasyBase = apiEasy.replace(' or slower', '');
      assert(
        `${distKey} ${raceTime} easy pace (mine=${myPaces.easy.mi} vs API=${apiEasyBase})`,
        myPaces.easy.mi,
        apiEasyBase
      );
    }

    const apiThresh = row.paces?.threshold?.mi;
    if (apiThresh) {
      assert(
        `${distKey} ${raceTime} threshold (mine=${myPaces.threshold.mi} vs API=${apiThresh})`,
        myPaces.threshold.mi,
        apiThresh
      );
    }
  }
} catch (err) {
  console.warn(`  ⚠  Could not load existing training-pace-tables.json: ${err.message}`);
  console.warn('     (Skipping Section 5 — file may not exist yet, run generation first)');
}

// ============================================================================
// SUMMARY
// ============================================================================

console.log(`\n${'='.repeat(50)}`);
console.log(`Results: ${passed} passed, ${failed} failed`);

if (failed > 0) {
  console.error('\nFAIL — formula parity test did not pass. Do not run generation.');
  process.exit(1);
} else {
  console.log('\nPASS — formula matches known backend outputs. Safe to generate data.');
}
